// Libro Diario: cada linea de asiento contable
var now = new Date();
var y = now.getFullYear();
var m = String(now.getMonth() + 1).padStart(2, '0');
var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();
var startDate = '20250101';
var endDate = y + m + String(lastDay).padStart(2, '0');
var sync_uuid = (Date.now().toString(36).toUpperCase().slice(-4) + Math.random().toString(36).substring(2,6).toUpperCase() + Math.random().toString(36).substring(2,6).toUpperCase());
msg.startDate = startDate; msg.endDate = endDate; msg.sync_uuid = sync_uuid;

var q = ""
+ "SELECT \n"
+ "    SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) AS FECHA,\n"
+ "    V_TRCONTABLE_.NUMERODOCUMENTO AS ASIENTO,\n"
+ "    COALESCE(V_EZI_ASIENTOS_DETALLES.DETALLE, V_TRCONTABLE_.DETALLE) AS DESCRIPCION,\n"
+ "    V_EZI_CUENTAS.CODIGO + ' ' + V_EZI_CUENTAS.DESCRIPCION AS CUENTA,\n"
+ "    ISNULL(SUM(V_VALOR_.IMPORTE), 0) AS DEBE,\n"
+ "    ISNULL(SUM(V_VALOR_1.IMPORTE), 0) AS HABER,\n"
+ "    ISNULL(V_UNIDADOPERATIVA_.NOMBRE, '') AS UNIDAD_NEGOCIO,\n"
+ "    '' AS REFERENCIA\n"
+ "FROM V_TRCONTABLE_\n"
+ "INNER JOIN V_ITEMCONTABLE_ ON V_TRCONTABLE_.ITEMSTRANSACCION_ID = V_ITEMCONTABLE_.BO_PLACE_ID\n"
+ "INNER JOIN V_VALOR_ ON V_ITEMCONTABLE_.DEBE_ID = V_VALOR_.ID\n"
+ "INNER JOIN V_VALOR_ AS V_VALOR_1 ON V_ITEMCONTABLE_.HABER_ID = V_VALOR_1.ID\n"
+ "INNER JOIN V_EZI_CUENTAS ON V_ITEMCONTABLE_.REFERENCIA_ID = V_EZI_CUENTAS.ID\n"
+ "LEFT OUTER JOIN V_EZI_ASIENTOS_DETALLES ON V_TRCONTABLE_.ID = V_EZI_ASIENTOS_DETALLES.ID\n"
+ "LEFT OUTER JOIN V_UNIDADOPERATIVA_ ON V_TRCONTABLE_.UNIDADOPERATIVA_ID = V_UNIDADOPERATIVA_.ID\n"
+ "WHERE SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) >= '" + startDate + "'\n"
+ "  AND SUBSTRING(V_TRCONTABLE_.FECHAAPLICACION, 1, 8) <= '" + endDate + "'\n"
+ "  AND V_EZI_CUENTAS.CODIGO BETWEEN '0' AND '9'\n"
+ "  AND V_TRCONTABLE_.ESTADO = 'C'\n"
+ "GROUP BY V_TRCONTABLE_.FECHAAPLICACION, V_TRCONTABLE_.NUMERODOCUMENTO,\n"
+ "    COALESCE(V_EZI_ASIENTOS_DETALLES.DETALLE, V_TRCONTABLE_.DETALLE),\n"
+ "    V_EZI_CUENTAS.CODIGO, V_EZI_CUENTAS.DESCRIPCION, V_UNIDADOPERATIVA_.NOMBRE\n"
+ "ORDER BY FECHA DESC, ASIENTO;\n";

msg.payload = q;
node.warn('[Sync-LD] Preparando sync ' + sync_uuid + ' ' + startDate + '-' + endDate);
return msg;

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var timestamp = new Date().toISOString();
msg._syncInfo = { sync_uuid: sync_uuid, periodo: (msg.startDate||'')+'-'+(msg.endDate||''), timestamp: timestamp };

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-LD] Sin datos. Se omite escritura.');
  msg._syncInfo.empty = true; msg.payload = null; return msg;
}

// Columnas A-I: FECHA|ASIENTO|DESCRIPCION|CTA_DEBE|CTA_HABER|IMPORTE|REF|UNIDAD_NEGOCIO|SYNC_UUID
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i]; if (!r) continue;
  var debe = parseFloat(r.DEBE) || 0;
  var haber = parseFloat(r.HABER) || 0;
  var importe = debe > haber ? debe : haber;
  if (importe === 0) continue;
  var cuenta = (r.CUENTA || '').toString().trim();
  data.push([
    (r.FECHA || '').toString().trim(),          // A: FECHA
    (r.ASIENTO || '').toString().trim(),        // B: ASIENTO
    (r.DESCRIPCION || '').toString().trim(),    // C: DESCRIPCION
    debe > haber ? cuenta : '',                 // D: CTA_DEBE
    haber > debe ? cuenta : '',                 // E: CTA_HABER
    importe,                                     // F: IMPORTE
    (r.REFERENCIA || '').toString().trim(),     // G: REF
    (r.UNIDAD_NEGOCIO || '').toString().trim(), // H: UNIDAD_NEGOCIO
    sync_uuid                                    // I: SYNC_UUID
  ]);
}

msg._sheetData = data;
msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-LD] ' + data.length + ' lineas (9 cols A-I). UUID=' + sync_uuid);
return msg;

// El GSheet Clear sobreescribe msg.payload con la respuesta de la API
// Restaurar el array 2D desde _sheetData para que el Append funcione
if (msg._sheetData) {
  msg.payload = msg._sheetData;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-ld] Sync omitido: sin datos');
  return msg;
}
if (msg.error) {
  node.error('[Sync-ld] ERROR: ' + msg.error);
  return msg;
}
var updatedRange = '';
if (msg.payload && msg.payload.updates) updatedRange = msg.payload.updates.updatedRange || '';
node.warn('[Sync-ld] ✅ Sync exitoso — ' + (info.rowCount || 0) + ' filas → LibroDiario');
node.warn('[Sync-ld]    UUID: ' + (info.sync_uuid || '?') + ' | Rango: ' + updatedRange);
return msg;
